agent_output:
{
  "domain_analysis": {
    "business_context": "Smart Route Optimization is a shift-level feature that automatically plans and dynamically replans a driver's delivery sequence. It sits at the intersection of fleet management, delivery fulfillment, and customer communication. The feature couples route planning with real-time reactivity (replanning on new deliveries, failures, deviations) and imposes vehicle-class constraints to ensure physical and regulatory correctness.",
    "bounded_context": "This feature spans at least four bounded contexts: (1) Route Planning — owns route calculation, stop ordering, replanning triggers, and time estimates; (2) Fleet/Driver Management — owns driver shifts, zones, vehicle classes, and driver-vehicle assignments; (3) Delivery Fulfillment — owns delivery lifecycle (pending, in-progress, failed, completed) and zone assignment; (4) Customer Notification — owns notification triggers and the 'next N stops' proximity window. Each context has its own language and must communicate via well-defined integration events, not direct coupling.",
    "ubiquitous_language": [
      { "term": "Shift", "definition": "A bounded work period during which a driver is active and eligible for route assignment. A shift has a start and end. Route optimization is triggered at shift start." },
      { "term": "Zone", "definition": "A geographic partition of the service area. Deliveries and drivers are assigned to zones. A driver's zone determines which pending deliveries are candidates for their route." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated to minimize travel time/distance for a driver within their zone for their current shift." },
      { "term": "Pending Delivery", "definition": "A delivery that has been accepted into the system but not yet assigned to a driver's active route, or assigned but not yet attempted." },
      { "term": "Failed Delivery", "definition": "A delivery attempt that did not result in successful handoff to the recipient. Triggers route recalculation to remove or reschedule the stop." },
      { "term": "Route Deviation", "definition": "When a driver's actual GPS position or stop sequence diverges from the suggested optimized route beyond an acceptable threshold." },
      { "term": "Licensed Vehicle Class", "definition": "A classification of the vehicle a driver is operating (e.g., motorcycle, van, truck, freight). Determines which deliveries are physically and legally eligible for assignment." },
      { "term": "Delivery Vehicle Class Requirement", "definition": "The minimum or required vehicle class a delivery demands, based on package dimensions, weight, or cargo type." },
      { "term": "Next-N-Stops Window", "definition": "A proximity threshold (spec says 3 stops) in the route sequence that triggers customer notification. When a delivery enters this window, the customer is informed of imminent arrival." },
      { "term": "Estimated Stop Duration", "definition": "The default time budgeted per delivery stop (4 minutes baseline), used by the route optimizer to calculate ETAs. Overridable per zone by operations." },
      { "term": "Recalculation Trigger", "definition": "An event that forces the route optimizer to recompute the current route. Three defined triggers: new delivery in zone, failed delivery, driver deviation." },
      { "term": "Operations Override", "definition": "The ability of the operations team to adjust system defaults (e.g., stop duration) at the zone level without code changes." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A driver MUST NOT be assigned a delivery whose vehicle class requirement exceeds the driver's licensed vehicle class.",
      "invariant": true,
      "invariant_justification": "Violating this creates physical impossibility (a motorcycle cannot carry freight) and potential regulatory/legal liability. No business policy can override physics or licensing law.",
      "testable_assertion": "For every delivery on a driver's route, delivery.requiredVehicleClass <= driver.licensedVehicleClass."
    },
    {
      "id": "BR-2",
      "rule": "When a driver starts a shift, the system must automatically generate an optimized route from all pending deliveries in the driver's assigned zone.",
      "invariant": false,
      "invariant_justification": "This is a workflow trigger policy. The business could decide to allow manual route building or delay optimization. It does not corrupt state if skipped — it degrades efficiency.",
      "testable_assertion": "Within T seconds of a shift-start event, a Route entity exists for that driver containing only deliveries from their zone with status 'pending'."
    },
    {
      "id": "BR-3",
      "rule": "The route MUST be recalculated when a new pending delivery is added to the driver's active zone during their shift.",
      "invariant": false,
      "invariant_justification": "This is an optimization policy. The system remains consistent without it — the new delivery simply wouldn't be served until the next route generation. A VP could decide to batch recalculations instead.",
      "testable_assertion": "When a DeliveryCreated event is emitted for zone Z and a driver has an active route in zone Z, a RouteRecalculated event is emitted within T seconds incorporating the new delivery."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when a delivery on the active route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Optimization policy. Without recalculation, the driver would simply skip the stop. No data corruption occurs.",
      "testable_assertion": "When a DeliveryFailed event is emitted for a delivery on an active route, the route is recalculated excluding that delivery and a RouteRecalculated event is emitted."
    },
    {
      "id": "BR-5",
      "rule": "The route MUST be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "Optimization policy. Without it, the driver simply continues off-plan. ETAs become inaccurate but no invariant is violated.",
      "testable_assertion": "When a RouteDeviation event is detected, a new optimized route is calculated from the driver's current position to remaining undelivered stops."
    },
    {
      "id": "BR-6",
      "rule": "Customers must be notified when their delivery enters the next-3-stops window of the driver's active route.",
      "invariant": false,
      "invariant_justification": "Notification policy. Missing a notification degrades customer experience but does not corrupt delivery state.",
      "testable_assertion": "When a delivery transitions from position > 3 to position <= 3 in the active route (or is initially within the window), a CustomerNotification event is emitted for that delivery's recipient."
    },
    {
      "id": "BR-7",
      "rule": "The default estimated stop duration is 4 minutes per delivery stop.",
      "invariant": false,
      "invariant_justification": "Configurable business parameter. Explicitly designed to be overridable.",
      "testable_assertion": "When no zone-level override exists, the route optimizer uses 240 seconds as the stop duration for ETA calculations."
    },
    {
      "id": "BR-8",
      "rule": "The operations team can override the estimated stop duration on a per-zone basis.",
      "invariant": false,
      "invariant_justification": "Administrative policy. The override capability is a business decision, not a system integrity constraint.",
      "testable_assertion": "When an operations user sets stopDuration for zone Z to N minutes, all subsequent route calculations for zone Z use N minutes instead of the 4-minute default."
    },
    {
      "id": "BR-9",
      "rule": "A driver's route may only contain deliveries within their assigned zone.",
      "invariant": true,
      "invariant_justification": "Zone boundaries define operational territories, insurance coverage, and regulatory compliance. Cross-zone assignment breaks chain of responsibility and can violate local operating permits.",
      "testable_assertion": "For every delivery on a driver's route, delivery.zone == driver.assignedZone."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts a shift and there are 10 pending deliveries in their zone, all compatible with their vehicle class",
      "when": "The shift-start event is processed",
      "then": "An optimized route is created containing all 10 deliveries in an order that minimizes travel time/distance, with ETAs calculated using the zone's stop duration (default 4 min or override)"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 8 remaining stops",
      "when": "A new pending delivery is added to the driver's zone and it is compatible with the driver's vehicle class",
      "then": "The route is recalculated to include the new delivery, stop order is re-optimized, and ETAs are updated for all remaining stops"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route and delivery #4 is marked as failed",
      "when": "The DeliveryFailed event is processed",
      "then": "The route is recalculated excluding the failed delivery, remaining stops are re-optimized, and ETAs are updated"
    },
    {
      "id": "AC-4",
      "given": "A driver deviates from the suggested route (e.g., skips a stop or takes a different road)",
      "when": "The deviation is detected",
      "then": "The route is recalculated from the driver's current position to remaining undelivered stops in optimized order"
    },
    {
      "id": "AC-5",
      "given": "A driver has an active route and completes stop #N, causing delivery D to move from position 4 to position 3",
      "when": "The route position update is processed",
      "then": "A notification is sent to delivery D's customer indicating their delivery is within the next 3 stops"
    },
    {
      "id": "AC-6",
      "given": "A motorcycle driver in zone A and a pending freight delivery in zone A",
      "when": "The route is calculated for this driver",
      "then": "The freight delivery is excluded from the route; the system does not assign it to the motorcycle driver"
    },
    {
      "id": "AC-7",
      "given": "The operations team sets stop duration for zone B to 6 minutes",
      "when": "A route is calculated for a driver in zone B",
      "then": "All ETA calculations use 6 minutes per stop instead of the 4-minute default"
    },
    {
      "id": "AC-8",
      "given": "A driver starts a shift and there are pending deliveries in their zone, some incompatible with their vehicle class",
      "when": "The route is generated",
      "then": "Only vehicle-class-compatible deliveries are included in the route; incompatible deliveries remain in the pending pool for assignment to an eligible driver"
    },
    {
      "id": "AC-9",
      "given": "A route recalculation is triggered (new delivery, failure, or deviation) and the recalculated route changes which deliveries are in the next-3-stops window",
      "when": "The recalculated route is committed",
      "then": "Notifications are sent to any newly-entering customers in the next-3-stops window (but not re-sent to customers already notified)"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Driver starts shift with zero pending deliveries in their zone",
      "expected_behavior": "An empty route is created (or no route). The system must still listen for new deliveries in the zone and trigger route creation when one arrives."
    },
    {
      "scenario": "All remaining deliveries on a route fail",
      "expected_behavior": "The route becomes empty. The driver's shift remains active. The system should notify operations and keep listening for new deliveries."
    },
    {
      "scenario": "A new delivery is added to a zone but no active driver in that zone has a compatible vehicle class",
      "expected_behavior": "The delivery remains pending and unassigned. It must not be force-assigned to an incompatible driver. Operations should be alerted."
    },
    {
      "scenario": "Multiple recalculation triggers fire simultaneously (new delivery + deviation at the same time)",
      "expected_behavior": "The system must handle concurrent triggers without producing duplicate or conflicting routes. Only one recalculated route should result, incorporating all pending changes."
    },
    {
      "scenario": "Customer notification boundary: delivery oscillates between position 3 and 4 due to repeated recalculations",
      "expected_behavior": "The customer should be notified once when first entering the window. Subsequent recalculations that keep the delivery in the window must not re-send the notification."
    },
    {
      "scenario": "Driver is assigned to zone A but physically located in zone B at shift start",
      "expected_behavior": "The route is built from zone A deliveries (zone is a logical assignment, not GPS-based). The optimizer should account for the driver's actual starting position for the first leg."
    },
    {
      "scenario": "Operations sets stop duration override to 0 or a negative value",
      "expected_behavior": "The system must validate the override and reject non-positive values. Stop duration must be a positive number."
    },
    {
      "scenario": "Route recalculation is triggered mid-delivery (driver is at a stop)",
      "expected_behavior": "The current stop is not interrupted. Recalculation applies to remaining stops after the current one."
    },
    {
      "scenario": "A driver's vehicle class changes mid-shift (e.g., vehicle swap due to breakdown)",
      "expected_behavior": "The route must be recalculated, dropping any deliveries incompatible with the new vehicle class. Those deliveries return to the pending pool."
    },
    {
      "scenario": "A delivery is cancelled by the customer while on the driver's active route",
      "expected_behavior": "The spec does not mention cancellation as a recalculation trigger. This is a likely missing requirement — cancellation should probably trigger recalculation similar to failure."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, increases deliveries per shift (higher throughput per driver), and reduces overtime. The 4-minute stop duration baseline, if poorly calibrated, can cascade into missed SLAs and penalty costs. Vehicle class enforcement prevents costly mis-deliveries and potential cargo damage claims.",
    "operational": "Real-time recalculation adds significant computational load — each trigger fires an optimization run. Without debouncing or batching, rapid-fire triggers (e.g., 20 new deliveries in 1 minute) could overwhelm the optimizer. Operations override capability is critical for zone-specific tuning (e.g., dense urban zones need shorter stop durations, rural zones need longer). Zone-based partitioning simplifies the optimization problem but introduces cross-zone coordination challenges for boundary deliveries.",
    "user": "Customers get proactive 'almost there' notifications via the next-3-stops window, improving satisfaction and reducing 'where is my package' inquiries. However, if recalculations cause ETAs to fluctuate wildly, customer trust erodes. Drivers benefit from not having to manually plan routes but may resist if the optimizer produces unintuitive orderings.",
    "risk": "Vehicle class invariant violation is the highest risk — regulatory fines, insurance invalidation, and safety incidents. Route recalculation race conditions could produce inconsistent state. Notification spam from oscillating stop positions would degrade customer experience. The spec is silent on what 'optimized' means (shortest distance? fewest left turns? time-windowed deliveries?) which creates implementation ambiguity with material business impact.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Automated route assignment changes their workflow. Must trust the optimizer. Deviation detection may feel like surveillance. Vehicle class enforcement protects them from impossible assignments." },
      { "group": "Customers", "impact": "Receive proactive notifications improving visibility. ETA accuracy depends on stop duration calibration. May receive confusing updates if recalculations cause notification churn." },
      { "group": "Operations Team", "impact": "Gains zone-level tuning capability. Needs tooling to monitor route efficiency, override stop durations, and handle unassignable deliveries. Alert fatigue risk if edge cases produce frequent escalations." },
      { "group": "Dispatchers", "impact": "Automation reduces manual route planning work but shifts their role to exception handling. Need visibility into why the optimizer made specific decisions." },
      { "group": "Finance/Management", "impact": "Expects measurable improvement in deliveries-per-shift and fuel costs. Needs KPIs and reporting on route efficiency gains." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec is clear on triggers and constraints but ambiguous on critical details: the optimization objective function is undefined, deviation detection thresholds are unspecified, the relationship between zones and driver assignment is implicit, and delivery cancellation is not addressed as a trigger. Vehicle class hierarchy is mentioned by example but not formally defined. These ambiguities materially affect implementation correctness.",
    "high_confidence_areas": [
      "Vehicle class constraint is a hard invariant — unambiguous",
      "Three recalculation triggers are explicitly enumerated",
      "Next-3-stops notification window is clearly defined",
      "4-minute default with per-zone override is clear",
      "Zone-scoped route generation is clear"
    ],
    "low_confidence_areas": [
      "What 'optimized' means — no objective function defined (time, distance, priority, delivery windows?)",
      "How route deviation is detected and what threshold constitutes a deviation",
      "Whether delivery cancellation should trigger recalculation (likely yes, but spec is silent)",
      "Vehicle class hierarchy — only motorcycle vs freight is exemplified, full class taxonomy is undefined",
      "Whether multiple drivers can be active in the same zone simultaneously and how deliveries are partitioned among them",
      "What happens when a zone has no active drivers"
    ],
    "assumptions": [
      "Zone assignment is a logical/administrative property of both drivers and deliveries, not purely GPS-derived",
      "Vehicle class is a hierarchy where higher classes can handle lower-class deliveries (a van can deliver motorcycle-eligible packages)",
      "Only one route exists per driver per shift at any time",
      "Delivery cancellation is a missing requirement that should be addressed",
      "Recalculation is synchronous to the trigger — no explicit batching/debouncing is intended"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The optimization objective function is not defined. 'Optimized route' could mean shortest distance, shortest time, fewest turns, priority-weighted, or time-window constrained. This is not a detail — it is the core algorithm decision and different objectives produce materially different routes.",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team", "Finance/Management"],
      "options": [
        "Optimize for shortest total travel time",
        "Optimize for shortest total distance",
        "Optimize for delivery priority / SLA deadlines",
        "Multi-objective optimization with configurable weights"
      ],
      "recommendation": "Start with shortest travel time as the default objective, as it maximizes deliveries per shift. Add SLA-deadline constraints as a secondary factor. Make objective configurable per zone."
    },
    {
      "type": "ambiguity",
      "description": "Route deviation detection is undefined. What constitutes a 'deviation'? GPS distance from planned route? Skipping a stop? Visiting stops out of order? Each interpretation requires different detection mechanisms and produces different recalculation frequencies.",
      "affected_stakeholders": ["Drivers", "Operations Team"],
      "options": [
        "GPS-based: driver is more than X meters from the planned route for more than Y seconds",
        "Sequence-based: driver completes a stop that is not the next expected stop",
        "Both GPS and sequence deviation"
      ],
      "recommendation": "Implement sequence-based deviation (driver completes or skips stops out of order) as the primary trigger. GPS-based deviation adds complexity and surveillance concerns. Sequence deviation is simpler, less invasive, and directly actionable."
    },
    {
      "type": "missing_context",
      "description": "Delivery cancellation is not listed as a recalculation trigger, but it is a common real-world event. A cancelled delivery remaining on the route wastes driver time and produces incorrect customer notifications.",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team"],
      "options": [
        "Add cancellation as a 4th recalculation trigger",
        "Treat cancellation as equivalent to failure (remove from route, recalculate)",
        "Leave it out of scope for v1"
      ],
      "recommendation": "Add cancellation as a recalculation trigger. It is operationally equivalent to failure from the route optimizer's perspective and omitting it would be a visible gap on day one."
    },
    {
      "type": "ambiguity",
      "description": "Multi-driver zone partitioning is not addressed. If multiple drivers start shifts in the same zone, how are pending deliveries distributed? First-come-first-served? Geographic clustering? Load balancing? This fundamentally affects the optimization model.",
      "affected_stakeholders": ["Drivers", "Operations Team", "Customers"],
      "options": [
        "Geographic clustering: partition zone deliveries by sub-region proximity to each driver",
        "Load balancing: distribute evenly by count",
        "Priority-based: highest-priority deliveries go to the most experienced driver",
        "Single driver per zone constraint"
      ],
      "recommendation": "Geographic clustering within the zone is the most natural fit for route optimization. Assign each delivery to the nearest available driver, then optimize each driver's route independently."
    },
    {
      "type": "missing_context",
      "description": "Vehicle class taxonomy is not formally defined. The spec gives one example (motorcycle vs freight) but does not enumerate the full hierarchy or define compatibility rules (e.g., can a van driver deliver motorcycle-eligible packages?).",
      "affected_stakeholders": ["Drivers", "Operations Team"],
      "options": [
        "Define a strict hierarchy: motorcycle < van < truck < freight, where higher can serve lower",
        "Define independent classes with explicit compatibility matrix",
        "Defer to existing fleet management system's vehicle classification"
      ],
      "recommendation": "Define a hierarchical vehicle class model where each class can handle deliveries at or below its level. This matches physical reality (a truck can carry what a van can) and is simplest to implement and reason about."
    }
  ],

  "rejection_reasons": []
}

